	void pushPending(long id) {
		if (pendingSize == pending.length) {
			pending = Arrays.copyOf(pending, pendingSize * 2);
		}
		pending[pendingSize++] = id;
	}

	void release() {
		if (activeMark >= 0) {
			row.rollback(activeMark);
			activeMark = -1;
		}
	}

